const OAUTH_CONFIG = {
  clientId: 'mobile_app_client_123',
  // NO client_secret here — mobile apps are public clients
  authorizationEndpoint: 'https://auth.yourserver.com/authorize',
  tokenEndpoint: 'https://auth.yourserver.com/token',
  revocationEndpoint: 'https://auth.yourserver.com/revoke',
  // If you need a backend proxy for token exchange:
  backendTokenProxy: 'https://api.yourserver.com/auth/token-exchange',
  scopes: ['openid', 'profile', 'email'],
};

const SECURE_STORE_KEYS = {
  ACCESS_TOKEN: 'oauth_access_token',
  REFRESH_TOKEN: 'oauth_refresh_token',
  TOKEN_EXPIRY: 'oauth_token_expiry',
  ID_TOKEN: 'oauth_id_token',
};

// ============================================================
// Secure Token Storage using platform keychain/keystore
// ============================================================
class SecureTokenStorage {
  static async store(key, value) {
    if (!value || typeof value !== 'string') {
      throw new Error('Invalid value for secure storage');
    }
    await SecureStore.setItemAsync(key, value, {
      keychainAccessible: SecureStore.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
    });
  }

  static async retrieve(key) {
    try {
      return await SecureStore.getItemAsync(key);
    } catch (error) {
      // Do not log the actual token or error details that might contain secrets
      console.warn('Failed to retrieve secure item');
      return null;
    }
  }

  static async remove(key) {
    try {
      await SecureStore.deleteItemAsync(key);
    } catch (error) {
      console.warn('Failed to remove secure item');
    }
  }

  static async storeTokenResponse(tokenResponse) {
    const promises = [];

    if (tokenResponse.accessToken) {
      promises.push(
        SecureTokenStorage.store(
          SECURE_STORE_KEYS.ACCESS_TOKEN,
          tokenResponse.accessToken
        )
      );
    }

    if (tokenResponse.refreshToken) {
      promises.push(
        SecureTokenStorage.store(
          SECURE_STORE_KEYS.REFRESH_TOKEN,
          tokenResponse.refreshToken
        )
      );
    }

    if (tokenResponse.idToken) {
      promises.push(
        SecureTokenStorage.store(
          SECURE_STORE_KEYS.ID_TOKEN,
          tokenResponse.idToken
        )
      );
    }

    if (tokenResponse.expiresIn) {
      const expiryTime = Date.now() + tokenResponse.expiresIn * 1000;
      promises.push(
        SecureTokenStorage.store(
          SECURE_STORE_KEYS.TOKEN_EXPIRY,
          expiryTime.toString()
        )
      );
    }

    await Promise.all(promises);
  }

  static async clearAll() {
    await Promise.all(
      Object.values(SECURE_STORE_KEYS).map((key) =>
        SecureTokenStorage.remove(key)
      )
    );
  }

  static async isTokenExpired() {
    const expiry = await SecureTokenStorage.retrieve(
      SECURE_STORE_KEYS.TOKEN_EXPIRY
    );
    if (!expiry) return true;
    // Add 60-second buffer to account for clock skew and network latency
    return Date.now() >= parseInt(expiry, 10) - 60000;
  }
}

// ============================================================
// PKCE Helper — generates code_verifier and code_challenge
// ============================================================
class PKCEHelper {
  static async generateVerifier() {
    // Generate 32 random bytes (256 bits of entropy)
    const randomBytes = await Crypto.getRandomBytesAsync(32);
    return this.base64URLEncode(randomBytes);
  }

  static async generateChallenge(verifier) {
    const digest = await Crypto.digestStringAsync(
      Crypto.CryptoDigestAlgorithm.SHA256,
      verifier,
      { encoding: Crypto.CryptoEncoding.BASE64 }
    );
    // Convert standard base64 to base64url
    return digest
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=+$/, '');
  }

  static base64URLEncode(buffer) {
    const bytes = new Uint8Array(buffer);
    let binary = '';
    for (let i = 0; i < bytes.length; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary)
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=+$/, '');
  }

  static generateState() {
    // Generate a random state parameter to prevent CSRF
    const randomBytes = new Uint8Array(16);
    for (let i = 0; i < 16; i++) {
      randomBytes[i] = Math.floor(Math.random() * 256);
    }
    return this.base64URLEncode(randomBytes);
  }
}

// ============================================================
// Input Validation Utilities
// ============================================================
class InputValidator {
  static isValidAuthorizationCode(code) {
    if (!code || typeof code !== 'string') return false;
    // Authorization codes should be alphanumeric with limited special chars
    if (code.length > 2048) return false;
    return /^[a-zA-Z0-9._~+\/-]+=*$/.test(code);
  }

  static isValidState(state) {
    if (!state || typeof state !== 'string') return false;
    if (state.length > 512) return false;
    return /^[a-zA-Z0-9_-]+$/.test(state);
  }

  static isValidToken(token) {
    if (!token || typeof token !== 'string') return false;
    if (token.length > 8192) return false;
    // JWT format or opaque token
    return /^[a-zA-Z0-9._~+\/-]+=*$/.test(token);
  }

  static isValidRedirectUri(uri) {
    if (!uri || typeof uri !== 'string') return false;
    // Only allow our app's registered redirect URI scheme
    const allowedSchemes = ['exp://', 'myapp://'];
    return allowedSchemes.some((scheme) => uri.startsWith(scheme));
  }

  static sanitizeErrorMessage(message) {
    if (!message || typeof message !== 'string') return 'Unknown error';
    // Strip potentially sensitive information from error messages
    return message.substring(0, 200).replace(/[<>'"]/g, '');
  }
}

// ============================================================
// OAuth Service — handles the actual auth flows
// ============================================================
class OAuthService {
  /**
   * Option A: Direct PKCE token exchange (recommended if your auth server supports PKCE)
   * No client_secret needed on the device.
   */
  static async exchangeCodeWithPKCE(code, codeVerifier, redirectUri) {
    if (!InputValidator.isValidAuthorizationCode(code)) {
      throw new Error('Invalid authorization code format');
    }

    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      client_id: OAUTH_CONFIG.clientId,
      code: code,
      redirect_uri: redirectUri,
      code_verifier: codeVerifier,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => 'Token exchange failed');
      throw new Error(
        `Token exchange failed: ${InputValidator.sanitizeErrorMessage(errorText)}`
      );
    }

    const tokenResponse = await response.json();
    this.validateTokenResponse(tokenResponse);
    return tokenResponse;
  }

  /**
   * Option B: Backend proxy token exchange
   * Use this if your OAuth provider requires a client_secret.
   * The secret lives on YOUR server, never on the device.
   */
  static async exchangeCodeViaBackendProxy(code, codeVerifier, redirectUri) {
    if (!InputValidator.isValidAuthorizationCode(code)) {
      throw new Error('Invalid authorization code format');
    }

    const response = await fetch(OAUTH_CONFIG.backendTokenProxy, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        code: code,
        code_verifier: codeVerifier,
        redirect_uri: redirectUri,
      }),
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => 'Token exchange failed');
      throw new Error(
        `Token exchange failed: ${InputValidator.sanitizeErrorMessage(errorText)}`
      );
    }

    const tokenResponse = await response.json();
    this.validateTokenResponse(tokenResponse);
    return tokenResponse;
  }

  static async refreshAccessToken() {
    const refreshToken = await SecureTokenStorage.retrieve(
      SECURE_STORE_KEYS.REFRESH_TOKEN
    );

    if (!refreshToken || !InputValidator.isValidToken(refreshToken)) {
      throw new Error('No valid refresh token available');
    }

    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: OAUTH_CONFIG.clientId,
      refresh_token: refreshToken,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      // Refresh token may be revoked — clear stored tokens
      await SecureTokenStorage.clearAll();
      throw new Error('Token refresh failed — please log in again');
    }

    const tokenResponse = await response.json();
    this.validateTokenResponse(tokenResponse);
    await SecureTokenStorage.storeTokenResponse(tokenResponse);
    return tokenResponse;
  }

  static async revokeToken() {
    const accessToken = await SecureTokenStorage.retrieve(
      SECURE_STORE_KEYS.ACCESS_TOKEN
    );

    if (accessToken) {
      try {
        await fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: accessToken,
            client_id: OAUTH_CONFIG.clientId,
          }).toString(),
        });
      } catch (error) {
        // Best-effort revocation; always clear local tokens regardless
        console.warn('Token revocation request failed');
      }
    }

    await SecureTokenStorage.clearAll();
  }

  static validateTokenResponse(response) {
    if (!response || typeof response !== 'object') {
      throw new Error('Invalid token response');
    }

    if (!response.accessToken && !response.access_token) {
      throw new Error('Token response missing access_token');
    }

    const accessToken = response.accessToken || response.access_token;
    if (!InputValidator.isValidToken(accessToken)) {
      throw new Error('Invalid access token format in response');
    }
  }

  static async getValidAccessToken() {
    const isExpired = await SecureTokenStorage.isTokenExpired();

    if (isExpired) {
      try {
        const refreshed = await this.refreshAccessToken();
        return refreshed.access_token || refreshed.accessToken;
      } catch (error) {
        throw new Error('Session expired — please log in again');
      }
    }

    const token = await SecureTokenStorage.retrieve(
      SECURE_STORE_KEYS.ACCESS_TOKEN
    );

    if (!token) {
      throw new Error('No access token available');
    }

    return token;
  }
}

// ============================================================
// Authenticated API Client
// ============================================================
class ApiClient {
  static async request(url, options = {}) {
    // Validate URL is on our allowed API domain
    const allowedHosts = ['api.yourserver.com'];
    let parsedUrl;
    try {
      parsedUrl = new URL(url);
    } catch {
      throw new Error('Invalid API URL');
    }

    if (!allowedHosts.includes(parsedUrl.hostname)) {
      throw new Error('API request to unauthorized host');
    }

    if (parsedUrl.protocol !== 'https:') {
      throw new Error('API requests must use HTTPS');
    }

    const accessToken = await OAuthService.getValidAccessToken();

    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
      },
    });

    if (response.status === 401) {
      // Token might have been revoked server-side; try refresh
      try {
        const refreshed = await OAuthService.refreshAccessToken();
        const newToken = refreshed.access_token || refreshed.accessToken;

        return fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            Authorization: `Bearer ${newToken}`,
            'Content-Type': 'application/json',
          },
        });
      } catch {
        await SecureTokenStorage.clearAll();
        throw new Error('Authentication failed — please log in again');
      }
    }

    return response;
  }
}

