// React Native App Component
// ============================================================
export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [userInfo, setUserInfo] = useState(null);

  const redirectUri = AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'auth/callback',
  });

  // Check for existing valid session on app launch
  useEffect(() => {
    checkExistingSession();
  }, []);

  const checkExistingSession = async () => {
    try {
      const token = await SecureTokenStorage.retrieve(
        SECURE_STORE_KEYS.ACCESS_TOKEN
      );
      const isExpired = await SecureTokenStorage.isTokenExpired();

      if (token && !isExpired) {
        setIsAuthenticated(true);
      } else if (token && isExpired) {
        // Try to refresh
        try {
          await OAuthService.refreshAccessToken();
          setIsAuthenticated(true);
        } catch {
          await SecureTokenStorage.clearAll();
          setIsAuthenticated(false);
        }
      }
    } catch (error) {
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = useCallback(async () => {
    setIsLoading(true);

    try {
      // Generate PKCE pair
      const codeVerifier = await PKCEHelper.generateVerifier();
      const codeChallenge = await PKCEHelper.generateChallenge(codeVerifier);
      const state = PKCEHelper.generateState();

      // Build authorization URL
      const authUrl = new URL(OAUTH_CONFIG.authorizationEndpoint);
      authUrl.searchParams.set('response_type', 'code');
      authUrl.searchParams.set('client_id', OAUTH_CONFIG.clientId);
      authUrl.searchParams.set('redirect_uri', redirectUri);
      authUrl.searchParams.set('scope', OAUTH_CONFIG.scopes.join(' '));
      authUrl.searchParams.set('state', state);
      authUrl.searchParams.set('code_challenge', codeChallenge);
      authUrl.searchParams.set('code_challenge_method', 'S256');

      // Open system browser for authentication
      const result = await AuthSession.startAsync({
        authUrl: authUrl.toString(),
        returnUrl: redirectUri,
      });

      if (result.type !== 'success') {
        if (result.type === 'cancel' || result.type === 'dismiss') {
          // User cancelled — not an error
          return;
        }
        throw new Error('Authentication was not successful');
      }

      // Validate state parameter to prevent CSRF
      if (result.params.state !== state) {
        throw new Error(
          'State mismatch — possible CSRF attack. Authentication aborted.'
        );
      }

      // Check for error response from auth server
      if (result.params.error) {
        throw new Error(
          `Auth error: ${InputValidator.sanitizeErrorMessage(
            result.params.error_description || result.params.error
          )}`
        );
      }

      const authorizationCode = result.params.code;

      if (!InputValidator.isValidAuthorizationCode(authorizationCode)) {
        throw new Error('Invalid authorization code received');
      }

      // Exchange authorization code for tokens using PKCE
      // Use exchangeCodeWithPKCE if your auth server supports PKCE directly,
      // or exchangeCodeViaBackendProxy if a client_secret is required
      const tokenResponse = await OAuthService.exchangeCodeWithPKCE(
        authorizationCode,
        codeVerifier,
        redirectUri
      );

      // Store tokens securely in platform keychain/keystore
      await SecureTokenStorage.storeTokenResponse({
        accessToken: tokenResponse.access_token,
        refreshToken: tokenResponse.refresh_token,
        idToken: tokenResponse.id_token,
        expiresIn: tokenResponse.expires_in,
      });

      setIsAuthenticated(true);

      // Fetch user profile
      await fetchUserProfile();
    } catch (error) {
      Alert.alert(
        'Authentication Error',
        InputValidator.sanitizeErrorMessage(error.message)
      );
    } finally {
      setIsLoading(false);
    }
  }, [redirectUri]);

  const fetchUserProfile = async () => {
    try {
      const response = await ApiClient.request(
        'https://api.yourserver.com/userinfo'
      );

      if (response.ok) {
        const profile = await response.json();
        setUserInfo({
          name: typeof profile.name === 'string' ? profile.name.substring(0, 100) : 'User',
          email: typeof profile.email === 'string' ? profile.email.substring(0, 254) : '',
        });
      }
    } catch (error) {
      console.warn('Failed to fetch user profile');
    }
  };

  const handleLogout = useCallback(async () => {
    setIsLoading(true);
    try {
      await OAuthService.revokeToken();
      setIsAuthenticated(false);
      setUserInfo(null);
    } catch (error) {
      // Even if revocation fails, clear local state
      await SecureTokenStorage.clearAll();
      setIsAuthenticated(false);
      setUserInfo(null);
    } finally {
      setIsLoading(false);
    }
  }, []);

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#4A90D9" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  if (!isAuthenticated) {
    return (
      <View style={styles.container}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.subtitle}>Sign in to continue</Text>
        <TouchableOpacity style={styles.loginButton} onPress={handleLogin}>
          <Text style={styles.loginButtonText}>Sign In with OAuth</Text>
        </TouchableOpacity>
        <Text style={styles.securityNote}>
          🔒 Secured with PKCE — no secrets stored on device
        </Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>
        Hello, {userInfo?.name || 'User'}
      </Text>
      {userInfo?.email ? (
        <Text style={styles.subtitle}>{userInfo.email}</Text>
      ) : null}

      <TouchableOpacity
        style={styles.apiButton}
        onPress={async () => {
          try {
            const response = await ApiClient.request(
              'https://api.yourserver.com/protected-resource'
            );
            const data = await response.json();
            Alert.alert('API Response', JSON.stringify(data, null, 2).substring(0, 500));
          } catch (error) {
            Alert.alert(
              'API Error',
              InputValidator.sanitizeErrorMessage(error.message)
            );
            if (error.message.includes('log in again')) {
              setIsAuthenticated(false);
              setUserInfo(null);
            }
          }
        }}
      >
        <Text style={styles.apiButtonText}>Call Protected API</Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
        <Text style={styles.logoutButtonText}>Sign Out</Text>
      </TouchableOpacity>
    </View>
  );
}

